-- 4 شبهات كاملة البنية — عيّنة أولية مدروسة بعناية (لا الحصة الكاملة
-- 15 بعد). تعمّدت تأجيل الشبهات الأكثر حساسية تاريخيًا وفقهيًا (كسنّ
-- عائشة رضي الله عنها، الرق، حدّ الردة، تفاصيل الجهاد الفقهية) لأنها
-- تستحق تأليفًا متخصصًا من عالم شرعي، لا صياغة أولى قد تحمل تفاوتًا
-- دقيقًا عن الرأي العلمي المعتبر في مسائل بالغة الحساسية. راجع التقرير
-- النهائي. status='draft'، is_approved=false — إلزاميًا لكل صف.
INSERT INTO dawah_shubuhat (category_id, slug, title, complexity_level, shubha_text, why_spread, short_answer, detailed_refutation, assumption_correction, historical_linguistic_context, evidences, sources, objections_and_responses, conclusion, status, is_approved) VALUES

((SELECT id FROM dawah_categories WHERE slug='islamic-history'), 'spread-by-sword',
'هل انتشر الإسلام بالسيف؟', 'intermediate',
'"الإسلام دين انتشر بالإكراه والسيف، ولم ينتشر الناس فيه إلا خوفًا من القوة العسكرية للمسلمين."',
'انتشرت هذه الشبهة تاريخيًا في سياق الحروب الصليبية والاستشراق الاستعماري، وتكررت لاحقًا في الخطاب الإعلامي الحديث دون تدقيق تاريخي، مستفيدة من الخلط بين الفتوحات السياسية العسكرية (التي تشابه توسّع أي دولة في التاريخ) وبين اعتناق الناس للدين نفسه.',
'الفتوحات الإسلامية كانت توسّعًا سياسيًا لدولة، لا إكراهًا دينيًا على الأفراد — والدليل التاريخي أن أكبر الدول الإسلامية اليوم بالسكان (إندونيسيا، الهند، جنوب شرق آسيا عمومًا) لم تدخلها جيوش مسلمة فاتحة أصلًا، بل دخلها الإسلام عبر التجارة والدعوة السلمية.',
'يجب التمييز أولًا بين أمرين مختلفين تمامًا: (١) الفتوحات، وهي توسّع سياسي عسكري لدولة الخلافة شبيه بتوسّع أي إمبراطورية في التاريخ (الرومانية، الفارسية، لاحقًا الاستعمار الأوروبي)، هدفه بسط سلطة سياسية لا إكراه ديني؛ (٢) اعتناق الأفراد للإسلام، وهو أمر منفصل تمامًا نهى القرآن صراحة عن إكراه أحد عليه. الدليل التاريخي الأقوى على بطلان الشبهة: مناطق واسعة دخلها الإسلام بكثافة سكانية هائلة دون أي فتح عسكري إطلاقًا، أبرزها إندونيسيا (أكبر دولة مسلمة بالسكان في العالم اليوم) التي اعتنق أهلها الإسلام عبر التجار والدعاة المسلمين سلميًا لا عبر جيش. كذلك بقيت أقليات دينية كبيرة (مسيحيون، يهود، زرادشتيون) تحت الحكم الإسلامي قرونًا طويلة دون إكراه جماعي على تغيير دينها، وهو ما تشهد به استمرارية هذه الأقليات في المنطقة حتى اليوم بعد أكثر من ألف عام من الحكم الإسلامي.',
'الافتراض الخاطئ الشائع هو مساواة "الفتح العسكري لمنطقة" بـ"إكراه سكانها على تغيير دينهم" — وهذا خلط منهجي بين مفهومين مختلفين تمامًا في التاريخ. توسّع أي دولة عسكريًا لا يعني بالضرورة أنها تُكرِه كل الأفراد الخاضعين لسلطتها على اعتناق دين الحاكم، وهذا واضح في استمرار أقليات دينية كبرى تحت الحكم الإسلامي لقرون.',
'من الناحية اللغوية، الآية الأشهر في هذا الباب "لا إكراه في الدين" نزلت في المدينة بعد قيام الدولة الإسلامية وقوتها العسكرية، لا في مرحلة ضعف تُفسَّر معها كمجاملة مؤقتة — نزولها في هذا التوقيت تحديدًا يقوّي دلالتها على أنها مبدأ ثابت لا ظرفي.',
'[{"type":"quran","ref":"البقرة: ٢٥٦","text":"لَا إِكْرَاهَ فِي الدِّينِ ۖ قَد تَّبَيَّنَ الرُّشْدُ مِنَ الْغَيِّ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"لكن هناك آيات تأمر بالقتال، فكيف تُنفى فكرة الإكراه؟","response":"آيات القتال في القرآن مرتبطة بسياق دفاعي أو سياسي محدد (رد اعتداء، حماية دولة ناشئة)، وهي في باب السياسة والحرب بين الدول لا في باب إكراه الأفراد على تغيير معتقدهم الشخصي — وهذا الفرق دقيق ويستحق مقالًا مستقلًا لتفصيله بأدلته الكاملة."}]'::jsonb,
'انتشار الإسلام الفعلي بين مئات الملايين من البشر عبر التاريخ وحتى اليوم يتم غالبًا بالاقتناع الفردي، لا بالسيف — والدليل الأقوى على ذلك مناطق دخلها الإسلام سلميًا بالكامل دون أي فتح عسكري.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'hijab-oppression',
'هل الحجاب أداة قمع للمرأة؟', 'basic',
'"الحجاب فرضه الرجال على المرأة لتقييد حريتها والسيطرة على جسدها، وليس له علاقة حقيقية بالدين."',
'انتشرت هذه الشبهة من خلال ربط الحجاب إعلاميًا بحالات فردية لإكراه فعلي مورسته بعض المجتمعات أو الأنظمة باسم الدين، مع تعميم هذه الحالات الفردية على الحكم الشرعي نفسه، وأيضًا من خلط الحجاب الديني بعادات ثقافية محلية لا علاقة لها بالإسلام في بعض المناطق.',
'الحجاب في أصله الشرعي أمر إلهي للمرأة المسلمة البالغة الراشدة بمحض اختيارها الحر بعد قناعة، لا أداة يفرضها رجل على امرأة — وإكراه أي شخص عليه فعليًا مخالفة لمبدأ إسلامي أوسع هو عدم الإكراه في الدين أصلًا.',
'الحجاب في النص القرآني خطاب موجَّه للمرأة المؤمنة نفسها كتكليف شرعي شخصي، تمامًا كالصلاة والصيام، لا أمر موجَّه للرجل ليفرضه عليها بالقوة. حين تمارس بعض المجتمعات أو الأنظمة إكراهًا فعليًا على الحجاب (أو نقيضه: إكراهًا على خلعه)، فهذا انحراف عن الحكم الشرعي الأصلي الذي يقوم على الاختيار والقناعة، لا تطبيقًا صحيحًا له. ملايين النساء المسلمات حول العالم يخترن الحجاب بمحض إرادتهن ويصفنه بأنه تعبير عن هويتهن وحريتهن الدينية، لا قيدًا مفروضًا عليهن — وهذا يتعارض مباشرة مع تصوير الحجاب كأداة قمع بإطلاق.',
'الافتراض الخاطئ هو تعميم حالات إكراه فردية أو سياسات دولة معينة على الحكم الشرعي الأصلي نفسه — وهذا كتعميم إساءة استخدام أي قانون على القانون ذاته.',
NULL,
'[{"type":"quran","ref":"الأحزاب: ٥٩","text":"يَا أَيُّهَا النَّبِيُّ قُل لِّأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِن جَلَابِيبِهِنَّ ۚ ذَٰلِكَ أَدْنَىٰ أَن يُعْرَفْنَ فَلَا يُؤْذَيْنَ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"لماذا يُطلب من المرأة تغطية جسدها دون الرجل بنفس الدرجة؟","response":"الإسلام يطلب من الرجل أيضًا غض البصر والستر بما يناسبه (كتغطية العورة المحددة شرعًا له)، والتفاوت في تفاصيل اللباس بين الجنسين قائم في أغلب الثقافات الإنسانية أصلًا لأسباب متعددة، وهذه مسألة تستحق تفصيلًا مستقلًا لا اختزالًا هنا."}]'::jsonb,
'الحجاب في جوهره الشرعي تكليف ديني شخصي قائم على القناعة الحرة، لا أداة قمع — وإكراه أي شخص عليه أو على خلعه مخالفة لمبدأ عدم الإكراه في الدين نفسه.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='women-family'), 'polygamy-in-islam',
'لماذا يُباح تعدد الزوجات في الإسلام؟', 'intermediate',
'"الإسلام يسمح للرجل بالزواج من أربع نساء لإشباع رغباته، وهذا ظلم للمرأة وتفضيل غير عادل للرجل."',
'انتشرت هذه الشبهة من خلال عرض الإباحة المشروطة للتعدد كأنها أمر مطلق بلا قيود، وإغفال السياق التاريخي الذي نزل فيه الحكم، والخلط بين إباحة الشيء وبين إيجابه أو تفضيله كأصل.',
'تعدد الزوجات في الإسلام إباحة مشروطة بشروط صارمة (أهمها العدل التام بين الزوجات)، لا إيجاب ولا تفضيل، ونزل الحكم في سياق تاريخي محدد (بعد معارك خلّفت أعدادًا كبيرة من الأرامل واليتامى) كحل اجتماعي منظَّم لا كامتياز رغبوي.',
'الآية التي أباحت التعدد نزلت مقترنة بشرط العدل الصارم، وفي السياق التاريخي المباشر بعد غزوة أُحُد التي خلّفت عددًا كبيرًا من الأرامل والأيتام في مجتمع المدينة، فكان التعدد المنظَّم بشروط وسيلة اجتماعية لضمان الكفالة والحماية لهؤلاء النساء والأيتام بدل تركهن بلا عائل في مجتمع تلك الحقبة. كذلك فإن الأصل الذي يقرره القرآن نفسه هو الزواج بواحدة، والتعدد استثناء مشروط لا قاعدة، وقد نص القرآن صراحة أن العدل التام بين الزوجات أمر بالغ الصعوبة، وهو ما يجعل التعدد في التطبيق العملي محدودًا لمن يثق فعلًا بقدرته على تحقيق هذا العدل، لا بابًا مفتوحًا بلا ضابط.',
'الافتراض الخاطئ هو تصوير التعدد كأصل مُفضَّل أو حق مطلق بلا قيد، بينما النص القرآني نفسه يجعله استثناءً مشروطًا بعدل صعب التحقق، ويقرر أن الأصل الزواج بواحدة.',
'الخطاب القرآني في آية التعدد موجَّه أصلًا في سياق الحديث عن كفالة اليتامى، مما يوضح أن الحكمة الاجتماعية للحماية والكفالة كانت حاضرة في سياق نزول الحكم لا مجرد إباحة عامة منفصلة عن سياقها.',
'[{"type":"quran","ref":"النساء: ٣","text":"فَانكِحُوا مَا طَابَ لَكُم مِّنَ النِّسَاءِ مَثْنَىٰ وَثُلَاثَ وَرُبَاعَ ۖ فَإِنْ خِفْتُمْ أَلَّا تَعْدِلُوا فَوَاحِدَةً"}, {"type":"quran","ref":"النساء: ١٢٩","text":"وَلَن تَسْتَطِيعُوا أَن تَعْدِلُوا بَيْنَ النِّسَاءِ وَلَوْ حَرَصْتُمْ"}]'::jsonb,
'[]'::jsonb,
'[{"objection":"أليس هذا تفضيلًا للرجل الذي يستطيع التعدد دون المرأة؟","response":"عدم تناظر الحكم بين الجنسين هنا مرتبط بمنظومة الأسرة والنسب في الإسلام (كتحديد الأبوة والنفقة)، وهذه مسألة فقهية أوسع تستحق معالجة مستقلة مفصَّلة."}]'::jsonb,
'تعدد الزوجات في الإسلام إباحة استثنائية مشروطة بعدل صارم، نزلت في سياق اجتماعي محدد لحماية الأرامل واليتامى، لا تفضيلًا رغبويًا مطلقًا للرجل.',
'draft', false),

((SELECT id FROM dawah_categories WHERE slug='science-religion'), 'quran-science-claims',
'هل ادّعاءات الإعجاز العلمي في القرآن مبالَغ فيها؟', 'advanced',
'"المسلمون يحاولون فرض تفسيرات علمية حديثة على نص قديم بأثر رجعي، وكثير من ادّعاءات الإعجاز العلمي متكلَّفة أو غير دقيقة."',
'انتشر هذا النقد نتيجة انتشار بعض الكتابات الشعبية غير المنضبطة منهجيًا التي حاولت إسقاط كل اكتشاف علمي حديث على آيات قرآنية بتكلّف، دون تحرٍّ علمي دقيق أو ضوابط منهجية واضحة، مما أعطى انطباعًا عامًا سلبيًا حتى عن الحالات الأكثر توثيقًا ورصانة.',
'النقد له وجه حق جزئي: بعض الكتابات الشعبية فعلًا متكلَّفة منهجيًا وتستحق النقد، لكن هذا لا يُبطل القضية الأساسية بإطلاق — هناك إشارات قرآنية محدودة العدد ودقيقة الصياغة تستحق دراسة رصينة منضبطة لا حماسية.',
'من الأمانة العلمية أولًا الاعتراف بأن حقل "الإعجاز العلمي" شهد فعلًا تجاوزات منهجية من بعض الكتّاب غير المتخصصين، الذين حاولوا إسقاط كل نظرية علمية حديثة (حتى غير المستقرة علميًا بعد) على آيات بتكلّف واضح، وهذا نقد يستحق أن يُقَرّ به المسلم المنصف نفسه لا أن يُنكَر دفاعًا عن كل ادّعاء بلا تمييز. الموقف المنهجي السليم: يُنظَر في كل ادّعاء على حدة بمعيارين، هل دلالة الآية اللغوية تحتمل هذا المعنى فعلًا دون تكلّف تأويلي، وهل الحقيقة العلمية المُستشهَد بها مستقرة علميًا لا نظرية متغيرة؟ ما يجتاز هذين المعيارين قليل نسبيًا لكنه موجود، وما لا يجتازهما يجب التخلي عنه بصراحة لا الدفاع عنه عاطفيًا.',
'الافتراض الخاطئ الشائع في الاتجاهين معًا: إما رفض كل الإشارات جملة لمجرد وجود تجاوزات في بعضها، أو قبول كل ادّعاء جملة دفاعًا عن الدين دون تمحيص — والموقف المنهجي السليم هو تقييم كل حالة بمعيار علمي ولغوي مستقل.',
NULL,
'[]'::jsonb,
'[]'::jsonb,
'[{"objection":"أليس هذا اعترافًا بضعف حجة الإعجاز العلمي بالكامل؟","response":"لا، بل هو دعوة لتطبيقه بمنهجية علمية رصينة بدل الحماس غير المنضبط — وهذا الموقف نفسه هو الذي يتبناه كبار المتخصصين الجادّين في هذا المجال، لا تبنّي كل ادّعاء أو رفضه جملة."}]'::jsonb,
'النقد الموجَّه لبعض تجاوزات خطاب الإعجاز العلمي الشعبي له وجاهة جزئية تستحق الإقرار، لكنه لا يُبطل القضية الأساسية بإطلاق — الموقف السليم تقييم كل ادّعاء بمعيار علمي ولغوي دقيق مستقل، لا رفض أو قبول جماعي.',
'draft', false)
